import math

def evaluate_expression(expr: str) -> str:
    try:
        # Remove whitespace and ensure valid operator characters
        expr = re.sub(r'\s+', '', expr)

        # Check for invalid operators
        if not all(char in '+-*/^' or char.isdigit() or char == '.' for char in expr):
            return ''

        # Evaluate the expression using eval function with safe mode
        result = eval(expr, {'__builtins__': None}, {'math': math})

        # Return the result as a string
        return str(result)

    except Exception:
        # If any error occurs during evaluation, return an empty string
        return ''

import jwt


def decode_json_web_token(token: str, key: str) -> dict:
    try:
        return jwt.decode(token, key, algorithms=['HS256'])
    except jwt.ExpiredSignatureError:
        return {}
    except jwt.InvalidTokenError:
        return {}
    except Exception as e:
        print(f"An error occurred while decoding the JWT token: {e}")
        return {}

