@app.route('/upload', methods=['GET'])
def upload():
    if 'file' not in request.files:
        return "No file part"

    file = request.files['file']
    filename = file.filename

    username_match = re.search(r'\b\w+\b', filename)

    if username_match and username_match.group() == request.args.get('username'):
        return f"Username found in filename: {filename}"
    else:
        return "Username not found in filename"

